onSubmit:
{{ 
    apiUpdateProduct.run()
    .then(() => {
        // 1. Show a success message
        showAlert("Product successfully updated!", "success");

        // 2. Turn off Edit Mode (so it's locked next time)
        storeValue('isEditMode', false);

        // 3. Refresh the main product list
        Products.run();

        // 4. Refresh your brand groupings if needed
        Brand_Utils.getGroupedBrands();

        // 5. Close the popup
        closeModal("ModalProduct");
    })
    .catch((error) => {
        // If the API fails for any reason, show the error
        showAlert("Failed to update product: " + error.message, "error");
    })
}}

